def build_packet(payload: bytes, msg_type: int, msg_id: int, flags: int, frag_index: int = 0, frag_count: int = 1) -> bytes:
    header = struct.pack("!4sBBIHHI", MAGIC, msg_type & 0xFF, flags & 0xFF, _u32(msg_id), frag_index & 0xFFFF, frag_count & 0xFFFF, _u32(len(payload)))
    crc = struct.pack("!I", _u32(zlib.crc32(header + payload)))
    return header + payload + crc


def parse_packet(data: bytes) -> Optional[Dict[str, Any]]:
    if len(data) < 4 + 1 + 1 + 4 + 2 + 2 + 4 + 4:
        return None
    magic, msg_type, flags, msg_id, frag_index, frag_count, payload_len = struct.unpack("!4sBBIHHI", data[:18])
    if magic != MAGIC:
        return None
    total_len = 18 + payload_len + 4
    if len(data) != total_len:
        return None
    payload = data[18:18 + payload_len]
    recv_crc, = struct.unpack("!I", data[18 + payload_len:18 + payload_len + 4])
    calc_crc = _u32(zlib.crc32(data[:18] + payload))
    if recv_crc != calc_crc:
        return None
    return {
        "type": msg_type,
        "flags": flags,
        "id": msg_id,
        "frag_index": frag_index,
        "frag_count": frag_count,
        "payload": payload,
    }


def fragment_payload(payload: bytes, max_fragment_payload: int) -> List[bytes]:
    if len(payload) <= max_fragment_payload:
        return [payload]
    frags = []
    for i in range(0, len(payload), max_fragment_payload):
        frags.append(payload[i:i + max_fragment_payload])
    return frags


